mapper.insert:
insert into `point_balance` (user_id, current_points, total_earned, create_time, create_by, update_time,
                             update_by)
values (#{userId}, #{point}, #{point}, now(), #{createBy}, now(), #{updateBy});

mapper.update:
update point_balance
set current_points = current_points + #{point},
    total_earned = total_earned + #{point},
    update_time = now(),
    update_by = #{updateBy}
where user_id = #{userId}

UPDATE point_balance
SET current_points = current_points - #{points},
    total_spent = total_spent + #{points},
    update_time = NOW()
WHERE user_id = #{userId}
  AND current_points >= #{points}

mapper.select:
SELECT * FROM `point-detail`
WHERE user_id = #{userId}

    AND type = #{type}


    AND DATE(create_time) >= #{startDate}


    AND DATE(create_time) <= #{endDate}

ORDER BY create_time DESC
